var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"LEADER_XMAS_NULL_NULL","text":{"KOREA":"......그렇군요. 상황은 이해했습니다.","JPN":"……そうですか。状況は理解しました。","ENG":"... I see. I understand the situation.","TWN":"……原來如此，情況我已經瞭解了。"},"stage":{"bg":"X_MAS_HOUSE","slots":{"L":null,"C":{"char_id":"LEADER_XMAS_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"그러게 내가 말했잖아. 처음부터 그 녀석이 의심스러웠다니까?","JPN":"だから言ったじゃない。最初からあいつが怪しいって！","ENG":"I told you. He's been suspicious since the beginning!","TWN":"我剛開始就說過，那個傢伙非常可疑！"},"stage":{"bg":"X_MAS_HOUSE","slots":{"L":null,"C":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LEADER_XMAS_NULL_NULL","text":{"KOREA":"아직 주시윤 님이 범인이라고 확정된 것은 아닙니다.","JPN":"まだアキヤマ・シリュウさんが犯人だと決まったわけではありません。","ENG":"We still don't know if Mr. Shiyoon is the perpetrator.","TWN":"但現在還不能斷定周時雲就是兇手。"},"stage":{"bg":"X_MAS_HOUSE","slots":{"L":{"char_id":"LEADER_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"LEADER_XMAS_NULL_NULL","text":{"KOREA":"다른 이유가 있어서 싸운 것일 수도 있지 않나요?","JPN":"他の理由があって、戦っているということもありますから。","ENG":"It's also possible that he fought you for a different reason.","TWN":"說不定他有其他緣由才會這麼做。"},"stage":{"bg":"X_MAS_HOUSE","slots":{"L":{"char_id":"LEADER_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"하지만 유력한 용의자인 건 사실이죠.","JPN":"しかし、有力な容疑者であるのも事実です。","ENG":"Still, he's the most likely suspect.","TWN":"但他確實是最大的嫌疑人。"},"stage":{"bg":"X_MAS_HOUSE","slots":{"L":{"char_id":"LEADER_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"방금 전에도 무장 해제를 거부하고 도망쳤잖아요?","JPN":"さっきも武装解除を拒否して逃げたじゃないですか。","ENG":"Even now, he refused to disarm and ran away.","TWN":"妳都看到他剛剛拒絕解除武裝，然後就跑了！"},"stage":{"bg":"X_MAS_HOUSE","slots":{"L":{"char_id":"LEADER_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"LEADER_XMAS_NULL_NULL","text":{"KOREA":"무슨 말씀인지는 이해했습니다.","JPN":"何をおっしゃりたいのかは理解しました。","ENG":"I understand.","TWN":"我明白妳的意思。"},"stage":{"bg":"X_MAS_HOUSE","slots":{"L":null,"C":{"char_id":"LEADER_XMAS_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LEADER_XMAS_NULL_NULL","text":{"KOREA":"하지만 주시윤 님이 이런 짓을 저지를 만한 분이라면, 주인님께서 가까이 두셨을지 의문이군요.","JPN":"しかし、アキヤマ様がこのようなことをするお方でしたら、ご主人様が傍に置くでしょうか？","ENG":"But I doubt the Master would have kept Mr. Shiyoon so close if he was such a heinous man.","TWN":"但如果周時雲真是那樣的人，主人是不會和他走這麼近的。"},"stage":{"bg":"X_MAS_HOUSE","slots":{"L":null,"C":{"char_id":"LEADER_XMAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"끄응...... 주인님만 붙이면 만사 해결이라 속 편하겠어, 참.","JPN":"うっ……ご主人様を持ち出せば何でも解決できちゃうんだからいいもんよね。","ENG":"Gah, again with the Master!","TWN":"唉……一句主人就解決了所有事，真是輕鬆。"},"stage":{"bg":"X_MAS_HOUSE","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"그러면 베로니카 씨는 선배를 의심하지 않는 건가요?","JPN":"そしたら、ベロニカさんは先輩が怪しくないと言うのですか？","ENG":"Then, Veronica, don't you think he's the one?","TWN":"所以貝洛妮卡妳並不認為前輩是兇手？"},"stage":{"bg":"X_MAS_HOUSE","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"LEADER_XMAS_NULL_NULL","text":{"KOREA":"많은 용의점이 있지만, 범인으로 단정 짓기 전에 확인은 필요하다고 봅니다. ","JPN":"怪しい点は多いですが、犯人として断定する前に確認が必要だと思います。 ","ENG":"He's definitely suspicious, but I still think we should check before making any conclusion. ","TWN":"雖然有很多疑點，但在斷定他為兇手之前，還需要再確認一下。"},"stage":{"bg":"X_MAS_HOUSE","slots":{"L":{"char_id":"LEADER_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_XMAS_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L20_1","type":"dialog","speaker":"LEADER_XMAS_NULL_NULL","text":{"KOREA":"최선의 방법은 본인을 찾아 직접 이야기를 듣는 것이겠죠.","JPN":"最善の策としては、本人から直接話を聞くことでしょう。","ENG":"The best way would be to find and talk to him.","TWN":"最好的辦法，就是找到他，聽他解釋。"},"stage":{"bg":"X_MAS_HOUSE","slots":{"L":{"char_id":"LEADER_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_XMAS_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L21_1","type":"dialog","speaker":"TONFA_XMAS_NULL_NULL","text":{"KOREA":"모네도 최선을 다해 돕겠슴다!","JPN":"モネも最善を尽くすっすよ！","ENG":"Mone will help as best as I can, ma'am!","TWN":"莫妮會竭盡全力幫您的！"},"stage":{"bg":"X_MAS_HOUSE","slots":{"L":{"char_id":"LEADER_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_XMAS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"TONFA_XMAS_NULL_NULL","text":{"KOREA":"그런데 시윤님은 어디로 가신 검까?","JPN":"しかし、アキヤマ様はどこに行ったっすか？","ENG":"By the way, where did he go, ma'am?","TWN":"可是時雲大人到底去哪裡了？"},"stage":{"bg":"X_MAS_HOUSE","slots":{"L":{"char_id":"LEADER_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_XMAS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"그걸 알면 내가 가만 있겠어? 당장 미사일을 떨어뜨렸지.","JPN":"それがわかれば、こんなところでじっとしてると思う？　すぐにでもミサイルを撃ち込むわ。","ENG":"If I knew, I would have already dropped a missile on him.","TWN":"要是我知道他去哪裡了，還會放過他嗎？我恨不得馬上射個導彈。"},"stage":{"bg":"X_MAS_HOUSE","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L26_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"신중한 사람이니까 이렇게 여러 명이 모여 있을 때 무턱대고 공격하진 않을 거예요.","JPN":"慎重な人ですから、このようにみんなで集まっているときに、攻撃してくることはないでしょう。","ENG":"He's careful. He won't attack us when we're together like this.","TWN":"他是一個很慎重的人，這麼多人聚在一起，他是絕對不會貿然攻擊的。"},"stage":{"bg":"X_MAS_HOUSE","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"선배를 범인이라고 가정하면, 최대한 효율적으로 희생자를 만들 수 있게 움직이겠죠.","JPN":"先輩を犯人だと仮定すると、できるだけ効率的に犠牲者を作れるよう動くはずです。","ENG":"If he really is the perpetrator, he'll move in such a way that he can take care of us most effectively.","TWN":"如果前輩真的是兇手，肯定會以最大效率造出受害者。"},"stage":{"bg":"X_MAS_HOUSE","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};